// Expect body: { meta: {...}, data: [ ... offers ... ] }
const body = msg.payload || {};
const data = Array.isArray(body.data) ? body.data : [];
const meta = body.meta || {};
flow.set('filter_meta', meta);
flow.set('filter_data', data);
flow.set('filter_http_msg', msg);
msg.payload = { meta, data, count: data.length };
return msg;

// No RL agent: pass through unchanged.
// Input:  { meta: {...}, data: [ ... offers ... ] }  (e.g. 200_000 offers)
// Output: same payload as response.json
msg.payload = msg.payload || {};
msg.headers = msg.headers || {};
msg.headers['Content-Type'] = 'application/json';
return msg;

const input = msg.payload || {};
const meta = { ...(input.meta || {}), count: (input.data || []).length };
const data = input.data || [];
const httpMsg = flow.get('filter_http_msg') || msg;
httpMsg.payload = { meta, data };
httpMsg.headers = httpMsg.headers || {};
httpMsg.headers['Content-Type'] = 'application/json';
return httpMsg;
